func (h *akpPrivateKey) Has(name string) bool {
	h.mu.RLock()
	defer h.mu.RUnlock()
	switch name {
	case KeyTypeKey:
		return true
	case AlgorithmKey:
		return h.algorithm != nil
	case KeyIDKey:
		return h.keyID != nil
	case KeyOpsKey:
		return h.keyOps != nil
	case KeyUsageKey:
		return h.keyUsage != nil
	case AKPPrivKey:
		return h.priv != nil
	case AKPPubKey:
		return h.pub != nil
	case X509CertChainKey:
		return h.x509CertChain != nil
	case X509CertThumbprintKey:
		return h.x509CertThumbprint != nil
	case X509CertThumbprintS256Key:
		return h.x509CertThumbprintS256 != nil
	case X509URLKey:
		return h.x509URL != nil
	default:
		_, ok := h.privateParams[name]
		return ok
	}
}

func (h *akpPrivateKey) Field(name string) (any, bool) {
	h.mu.RLock()
	defer h.mu.RUnlock()
	switch name {
	case KeyTypeKey:
		return h.KeyType(), true
	case AlgorithmKey:
		if h.algorithm == nil {
			return nil, false
		}
		return *(h.algorithm), true
	case KeyIDKey:
		if h.keyID == nil {
			return nil, false
		}
		return *(h.keyID), true
	case KeyOpsKey:
		if h.keyOps == nil {
			return nil, false
		}
		return *(h.keyOps), true
	case KeyUsageKey:
		if h.keyUsage == nil {
			return nil, false
		}
		return *(h.keyUsage), true
	case AKPPrivKey:
		if h.priv == nil {
			return nil, false
		}
		return h.priv, true
	case AKPPubKey:
		if h.pub == nil {
			return nil, false
		}
		return h.pub, true
	case X509CertChainKey:
		if h.x509CertChain == nil {
			return nil, false
		}
		return h.x509CertChain, true
	case X509CertThumbprintKey:
		if h.x509CertThumbprint == nil {
			return nil, false
		}
		return *(h.x509CertThumbprint), true
	case X509CertThumbprintS256Key:
		if h.x509CertThumbprintS256 == nil {
			return nil, false
		}
		return *(h.x509CertThumbprintS256), true
	case X509URLKey:
		if h.x509URL == nil {
			return nil, false
		}
		return *(h.x509URL), true
	default:
		v, ok := h.privateParams[name]
		return v, ok
	}
}

func (h *akpPrivateKey) Set(name string, value any) error {
	h.mu.Lock()
	defer h.mu.Unlock()
	return h.setNoLock(name, value)
}

func (h *akpPrivateKey) setNoLock(name string, value any) error {
	switch name {
	case "kty":
		return nil
	case AlgorithmKey:
		switch v := value.(type) {
		case string, jwa.SignatureAlgorithm, jwa.KeyEncryptionAlgorithm, jwa.ContentEncryptionAlgorithm:
			tmp, err := jwa.KeyAlgorithmFrom(v)
			if err != nil {
				return fmt.Errorf(`invalid algorithm for %q key: %w`, AlgorithmKey, err)
			}
			h.algorithm = &tmp
		default:
			return fmt.Errorf(`invalid type for %q key: %T`, AlgorithmKey, value)
		}
		return nil
	case KeyIDKey:
		if v, ok := value.(string); ok {
			h.keyID = &v
			return nil
		}
		return fmt.Errorf(`invalid value for %s key: %T`, KeyIDKey, value)
	case KeyOpsKey:
		var acceptor KeyOperationList
		if err := acceptor.Accept(value); err != nil {
			return fmt.Errorf(`invalid value for %s key: %w`, KeyOpsKey, err)
		}
		h.keyOps = &acceptor
		return nil
	case KeyUsageKey:
		switch v := value.(type) {
		case KeyUsageType:
			switch v {
			case ForSignature, ForEncryption:
				tmp := v.String()
				h.keyUsage = &tmp
			default:
				return fmt.Errorf(`invalid key usage type %s`, v)
			}
		case string:
			h.keyUsage = &v
		default:
			return fmt.Errorf(`invalid key usage type %s`, v)
		}
	case AKPPrivKey:
		if v, ok := value.([]byte); ok {
			if v == nil {
				h.priv = nil
			} else {
				h.priv = make([]byte, len(v))
				copy(h.priv, v)
			}
			return nil
		}
		return fmt.Errorf(`invalid value for %s key: %T`, AKPPrivKey, value)
	case AKPPubKey:
		if v, ok := value.([]byte); ok {
			if v == nil {
				h.pub = nil
			} else {
				h.pub = make([]byte, len(v))
				copy(h.pub, v)
			}
			return nil
		}
		return fmt.Errorf(`invalid value for %s key: %T`, AKPPubKey, value)
	case X509CertChainKey:
		if v, ok := value.(*cert.Chain); ok {
			h.x509CertChain = v
			return nil
		}
		return fmt.Errorf(`invalid value for %s key: %T`, X509CertChainKey, value)
	case X509CertThumbprintKey:
		if v, ok := value.(string); ok {
			h.x509CertThumbprint = &v
			return nil
		}
		return fmt.Errorf(`invalid value for %s key: %T`, X509CertThumbprintKey, value)
	case X509CertThumbprintS256Key:
		if v, ok := value.(string); ok {
			h.x509CertThumbprintS256 = &v
			return nil
		}
		return fmt.Errorf(`invalid value for %s key: %T`, X509CertThumbprintS256Key, value)
	case X509URLKey:
		if v, ok := value.(string); ok {
			h.x509URL = &v
			return nil
		}
		return fmt.Errorf(`invalid value for %s key: %T`, X509URLKey, value)
	default:
		if h.privateParams == nil {
			h.privateParams = map[string]any{}
		}
		h.privateParams[name] = value
	}
	return nil
}

func (k *akpPrivateKey) Remove(key string) error {
	k.mu.Lock()
	defer k.mu.Unlock()
	switch key {
	case AlgorithmKey:
		k.algorithm = nil
	case KeyIDKey:
		k.keyID = nil
	case KeyOpsKey:
		k.keyOps = nil
	case KeyUsageKey:
		k.keyUsage = nil
	case AKPPrivKey:
		k.priv = nil
	case AKPPubKey:
		k.pub = nil
	case X509CertChainKey:
		k.x509CertChain = nil
	case X509CertThumbprintKey:
		k.x509CertThumbprint = nil
	case X509CertThumbprintS256Key:
		k.x509CertThumbprintS256 = nil
	case X509URLKey:
		k.x509URL = nil
	default:
		delete(k.privateParams, key)
	}
	return nil
}

func (dst *akpPrivateKey) cloneFrom(src *akpPrivateKey) {
	src.mu.RLock()
	defer src.mu.RUnlock()
	dst.mu.Lock()
	defer dst.mu.Unlock()
	if src.algorithm != nil {
		tmp := *(src.algorithm)
		dst.algorithm = &tmp
	} else {
		dst.algorithm = nil
	}
	if src.keyID != nil {
		tmp := *(src.keyID)
		dst.keyID = &tmp
	} else {
		dst.keyID = nil
	}
	if src.keyOps != nil {
		tmp := slices.Clone(*src.keyOps)
		dst.keyOps = &tmp
	} else {
		dst.keyOps = nil
	}
	if src.keyUsage != nil {
		tmp := *(src.keyUsage)
		dst.keyUsage = &tmp
	} else {
		dst.keyUsage = nil
	}
	if src.priv != nil {
		dst.priv = slices.Clone(src.priv)
	} else {
		dst.priv = nil
	}
	if src.pub != nil {
		dst.pub = slices.Clone(src.pub)
	} else {
		dst.pub = nil
	}
	if src.x509CertChain != nil {
		dst.x509CertChain = src.x509CertChain
	} else {
		dst.x509CertChain = nil
	}
	if src.x509CertThumbprint != nil {
		tmp := *(src.x509CertThumbprint)
		dst.x509CertThumbprint = &tmp
	} else {
		dst.x509CertThumbprint = nil
	}
	if src.x509CertThumbprintS256 != nil {
		tmp := *(src.x509CertThumbprintS256)
		dst.x509CertThumbprintS256 = &tmp
	} else {
		dst.x509CertThumbprintS256 = nil
	}
	if src.x509URL != nil {
		tmp := *(src.x509URL)
		dst.x509URL = &tmp
	} else {
		dst.x509URL = nil
	}
	if len(src.privateParams) > 0 {
		dst.privateParams = make(map[string]any, len(src.privateParams))
		for k, v := range src.privateParams {
			dst.privateParams[k] = v
		}
	} else {
		dst.privateParams = nil
	}
}

func (k *akpPrivateKey) Clone() (Key, error) {
	dst := newAKPPrivateKey()
	dst.cloneFrom(k)
	return dst, nil
}

func (k *akpPrivateKey) DecodeCtx() json.DecodeCtx {
	k.mu.RLock()
	defer k.mu.RUnlock()
	return k.dc
}

func (k *akpPrivateKey) SetDecodeCtx(dc json.DecodeCtx) {
	k.mu.Lock()
	defer k.mu.Unlock()
	k.dc = dc
}

func (h *akpPrivateKey) UnmarshalJSON(buf []byte) (retErr error) {
	h.mu.Lock()
	defer h.mu.Unlock()
	h.algorithm = nil
	h.keyID = nil
	h.keyOps = nil
	h.keyUsage = nil
	h.priv = nil
	h.pub = nil
	h.x509CertChain = nil
	h.x509CertThumbprint = nil
	h.x509CertThumbprintS256 = nil
	h.x509URL = nil
	defer func() {
		if retErr != nil {
			clear(h.priv)
			h.priv = nil
			clear(h.pub)
			h.pub = nil
		}
	}()
	dec := json.NewDecoder(bytes.NewReader(buf))
	tok, err := dec.ReadToken()
	if err != nil {
		return fmt.Errorf(`error reading token: %w`, err)
	}
	if tok.Kind() != '{' {
		return fmt.Errorf(`expected '{' but got '%c'`, tok.Kind())
	}
	for dec.PeekKind() != '}' {
		tok, err := dec.ReadToken()
		if err != nil {
			return fmt.Errorf(`error reading token: %w`, err)
		}
		switch tok.String() {
		case KeyTypeKey:
			val, err := json.ReadNextStringToken(dec, h.dc)
			if err != nil {
				return fmt.Errorf(`error reading token: %w`, err)
			}
			if val != jwa.AKP().String() {
				return fmt.Errorf(`invalid kty value for RSAPublicKey (%s)`, val)
			}
		case AlgorithmKey:
			// "alg" is an informational hint stored as-is, not validated against the key type here; see [ParseKey] for rationale.
			var s string
			if err := json.UnmarshalDecode(dec, &s); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, AlgorithmKey, err)
			}
			alg, err := jwa.KeyAlgorithmFrom(s)
			if err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, AlgorithmKey, err)
			}
			h.algorithm = &alg
		case KeyIDKey:
			if err := json.AssignNextStringToken(&h.keyID, dec, h.dc); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, KeyIDKey, err)
			}
		case KeyOpsKey:
			var decoded KeyOperationList
			if err := json.UnmarshalDecode(dec, &decoded); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, KeyOpsKey, err)
			}
			h.keyOps = &decoded
		case KeyUsageKey:
			val, err := json.ReadNextStringToken(dec, h.dc)
			if err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, KeyUsageKey, err)
			}
			var acceptor KeyUsageType
			if err := acceptor.Accept(val); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, KeyUsageKey, err)
			}
			tmp := acceptor.String()
			h.keyUsage = &tmp
		case AKPPrivKey:
			if err := json.AssignNextBytesToken(&h.priv, dec); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, AKPPrivKey, err)
			}
		case AKPPubKey:
			if err := json.AssignNextBytesToken(&h.pub, dec); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, AKPPubKey, err)
			}
		case X509CertChainKey:
			var decoded cert.Chain
			if err := json.UnmarshalDecode(dec, &decoded); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, X509CertChainKey, err)
			}
			h.x509CertChain = &decoded
		case X509CertThumbprintKey:
			if err := json.AssignNextStringToken(&h.x509CertThumbprint, dec, h.dc); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, X509CertThumbprintKey, err)
			}
		case X509CertThumbprintS256Key:
			if err := json.AssignNextStringToken(&h.x509CertThumbprintS256, dec, h.dc); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, X509CertThumbprintS256Key, err)
			}
		case X509URLKey:
			if err := json.AssignNextStringToken(&h.x509URL, dec, h.dc); err != nil {
				return fmt.Errorf(`failed to decode value for key %s: %w`, X509URLKey, err)
			}
		default:
			fieldName := tok.String()
			raw, err := dec.ReadValue()
			if err != nil {
				return fmt.Errorf(`could not read value for field %s: %w`, fieldName, err)
			}
			if dc := h.dc; dc != nil {
				if localReg := dc.Registry(); localReg != nil {
					decoded, err := localReg.Decode(fieldName, raw)
					if err == nil {
						h.setNoLock(fieldName, decoded)
						continue
					}
				}
			}
			decoded, err := fieldRegistry.Decode(fieldName, raw)
			if err == nil {
				h.setNoLock(fieldName, decoded)
				continue
			}
			return fmt.Errorf(`could not decode field %s: %w`, fieldName, err)
		}
	}
	// consume closing '}'
	if _, err := dec.ReadToken(); err != nil {
		return fmt.Errorf(`error reading closing token: %w`, err)
	}
	if h.priv == nil {
		return fmt.Errorf(`required field priv is missing`)
	}
	if h.pub == nil {
		return fmt.Errorf(`required field pub is missing`)
	}
	return nil
}

func (h *akpPrivateKey) MarshalJSON() ([]byte, error) {
	pairs := getFieldPairList()
	{
		v, err := json.Marshal(jwa.AKP())
		if err != nil {
			return nil, fmt.Errorf(`failed to marshal field %q: %w`, KeyTypeKey, err)
		}
		pairs = append(pairs, fieldPair{Name: KeyTypeKey, Value: v})
	}
	h.mu.RLock()
	defer h.mu.RUnlock()
	if h.algorithm != nil {
		{
			v, err := json.Marshal(*(h.algorithm))
			if err != nil {
				return nil, fmt.Errorf(`failed to marshal field %q: %w`, AlgorithmKey, err)
			}
			pairs = append(pairs, fieldPair{Name: AlgorithmKey, Value: v})
		}
	}
	if h.keyID != nil {
		{
			v, err := json.Marshal(*(h.keyID))
			if err != nil {
				return nil, fmt.Errorf(`failed to marshal field %q: %w`, KeyIDKey, err)
			}
			pairs = append(pairs, fieldPair{Name: KeyIDKey, Value: v})
		}
	}
	if h.keyOps != nil {
		{
			v, err := json.Marshal(*(h.keyOps))
			if err != nil {
				return nil, fmt.Errorf(`failed to marshal field %q: %w`, KeyOpsKey, err)
			}
			pairs = append(pairs, fieldPair{Name: KeyOpsKey, Value: v})
		}
	}
	if h.keyUsage != nil {
		{
			v, err := json.Marshal(*(h.keyUsage))
			if err != nil {
				return nil, fmt.Errorf(`failed to marshal field %q: %w`, KeyUsageKey, err)
			}
			pairs = append(pairs, fieldPair{Name: KeyUsageKey, Value: v})
		}
	}
	if h.priv != nil {
		{
			v, err := json.Marshal(base64.EncodeToString(h.priv))
			if err != nil {
				return nil, fmt.Errorf(`failed to marshal field %q: %w`, AKPPrivKey, err)
			}
			pairs = append(pairs, fieldPair{Name: AKPPrivKey, Value: v})
		}
	}
	if h.pub != nil {
		{
			v, err := json.Marshal(base64.EncodeToString(h.pub))
			if err != nil {
				return nil, fmt.Errorf(`failed to marshal field %q: %w`, AKPPubKey, err)
			}
			pairs = append(pairs, fieldPair{Name: AKPPubKey, Value: v})
		}
	}
	if h.x509CertChain != nil {
		{
			v, err := json.Marshal(h.x509CertChain)
			if err != nil {
				return nil, fmt.Errorf(`failed to marshal field %q: %w`, X509CertChainKey, err)
			}
			pairs = append(pairs, fieldPair{Name: X509CertChainKey, Value: v})
		}
	}
	if h.x509CertThumbprint != nil {
		{
			v, err := json.Marshal(*(h.x509CertThumbprint))
			if err != nil {
				return nil, fmt.Errorf(`failed to marshal field %q: %w`, X509CertThumbprintKey, err)
			}
			pairs = append(pairs, fieldPair{Name: X509CertThumbprintKey, Value: v})
		}
	}
	if h.x509CertThumbprintS256 != nil {
		{
			v, err := json.Marshal(*(h.x509CertThumbprintS256))
			if err != nil {
				return nil, fmt.Errorf(`failed to marshal field %q: %w`, X509CertThumbprintS256Key, err)
			}
			pairs = append(pairs, fieldPair{Name: X509CertThumbprintS256Key, Value: v})
		}
	}
	if h.x509URL != nil {
		{
			v, err := json.Marshal(*(h.x509URL))
			if err != nil {
				return nil, fmt.Errorf(`failed to marshal field %q: %w`, X509URLKey, err)
			}
			pairs = append(pairs, fieldPair{Name: X509URLKey, Value: v})
		}
	}
	for k, v := range h.privateParams {
		switch bv := v.(type) {
		case []byte:
			encoded, err := json.Marshal(base64.EncodeToString(bv))
			if err != nil {
				return nil, fmt.Errorf(`failed to marshal field %q: %w`, k, err)
			}
			pairs = append(pairs, fieldPair{Name: k, Value: encoded})
		default:
			encoded, err := json.Marshal(v)
			if err != nil {
				return nil, fmt.Errorf(`failed to marshal field %q: %w`, k, err)
			}
			pairs = append(pairs, fieldPair{Name: k, Value: encoded})
		}
	}

	slices.SortFunc(pairs, fieldPairLess)
	buf := pool.BytesBuffer().Get()
	defer pool.BytesBuffer().Put(buf)
	buf.WriteByte('{')
	for i, p := range pairs {
		if i > 0 {
			buf.WriteByte(',')
		}
		buf.WriteByte('"')
		buf.WriteString(p.Name)
		buf.WriteByte('"')
		buf.WriteByte(':')
		buf.Write(p.Value.([]byte))
	}
	buf.WriteByte('}')
	putFieldPairList(pairs)
	ret := make([]byte, buf.Len())
	copy(ret, buf.Bytes())
	return ret, nil
}

func (h *akpPrivateKey) Keys() []string {
	h.mu.RLock()
	defer h.mu.RUnlock()
	keys := make([]string, 0, 10+len(h.privateParams))
	keys = append(keys, KeyTypeKey)
	if h.algorithm != nil {
		keys = append(keys, AlgorithmKey)
	}
	if h.keyID != nil {
		keys = append(keys, KeyIDKey)
	}
	if h.keyOps != nil {
		keys = append(keys, KeyOpsKey)
	}
	if h.keyUsage != nil {
		keys = append(keys, KeyUsageKey)
	}
	if h.priv != nil {
		keys = append(keys, AKPPrivKey)
	}
	if h.pub != nil {
		keys = append(keys, AKPPubKey)
	}
	if h.x509CertChain != nil {
		keys = append(keys, X509CertChainKey)
	}
	if h.x509CertThumbprint != nil {
		keys = append(keys, X509CertThumbprintKey)
	}
	if h.x509CertThumbprintS256 != nil {
		keys = append(keys, X509CertThumbprintS256Key)
	}
	if h.x509URL != nil {
		keys = append(keys, X509URLKey)
	}
	for k := range h.privateParams {
		keys = append(keys, k)
	}
	return keys
}

func init() {
	registry.Register(jwa.AKP().String(), registry.Constructor{
		Public:  func() any { return newAKPPublicKey() },
		Private: func() any { return newAKPPrivateKey() },
	})
}
